package com.example

import com.example.Question

object QuestionDatabase {

    private fun q(
        lvl: Int,
        qBn: String, qEn: String,
        optBn: String, optEn: String,
        correct: Int,
        type: String = "trick",
        expBn: String, expEn: String
    ): Question {
        val stage = when {
            lvl <= 50 -> 1
            lvl <= 100 -> 2
            lvl <= 150 -> 3
            else -> 4
        }
        return Question(
            id = lvl, stage = stage, level = lvl,
            questionBn = qBn, questionEn = qEn,
            type = type,
            optionsBn = optBn.split("|").map { it.trim() },
            optionsEn = optEn.split("|").map { it.trim() },
            correctIndex = correct,
            isTrick = type != "normal",
            explanationBn = expBn,
            explanationEn = expEn
        )
    }

